}

function buildObjecionesHTML(d) {
  const objs = Array.isArray(d.objeciones_detalle) ? d.objeciones_detalle : [];
  if (!objs.length) return null;
  const items = objs.map((o, i) => `<strong>${i + 1}. "${esc(o.objecion)}"</strong> → <span style="color:#a3a3a3;">Respondiste:</span> "${esc(o.respuesta)}"`).join("<br><br>");
  return items;
}

function bulletize(text) {
  // Si el texto trae separador " | " lo convierte en bullets negrita; si no,
  // lo deja como un párrafo simple (nunca inventa contenido).
  if (!text) return "";
  const parts = String(text).split("|").map(s => s.trim()).filter(Boolean);
  if (parts.length <= 1) return esc(text);
  return parts.map(p => `• ${esc(p)}`).join("<br>");
}

function buildActivityRows(d) {
  const mods = String(d.modulos_practicados || "").split(",").map(s => s.trim()).filter(Boolean);
  if (!mods.length) return "";
  return mods.map(m => `<tr><td valign="top" width="26" style="font-family:Inter,sans-serif;font-size:14px;color:#5cc08a;padding:0 0 10px 0;">✓</td>
    <td valign="top" style="font-family:Inter,sans-serif;font-size:14px;line-height:20px;color:#E5E5E5;padding:0 0 10px 0;">${esc(m)}</td></tr>`).join("");
}

