// El audio se descarga en el nodo HTTP Request "Fetch Audio HTTP" (binario
// en la propiedad "data"). Aqui solo se decide si hay audio valido y se
// reenvia el binario intacto -- el Code node de esta instancia n8n no puede
// tocar bytes (sin fetch, sin $helpers, sin require de modulos http/https).

const prep = $node["Preparar Datos"].json;
const conversationId = prep.conversation_id;
const employeeName = String(prep.employee_name || 'sesion').replace(/[^a-zA-Z0-9_-]+/g, '_');

if (!conversationId || String(conversationId).startsWith('AUTO_')) {
  return [{ json: { success: false, error: 'No conversation_id (dato fallback/test, no hay audio real que descargar)' } }];
}

const item = $input.first();
if (!item.binary || !item.binary.data) {
  return [{ json: { success: false, error: 'Fetch Audio HTTP no devolvio binario (revisa ese nodo / conversation_id invalido)' } }];
}

return [{
  json: {
    success: true,
    conversation_id: conversationId,
    audio_filename: `VTC_${employeeName}_${conversationId}.mp3`
  },
  binary: { data: item.binary.data }
}];

// Ya no arma un array de contenido base64: el nodo "Send an Email" (SMTP)
// adjunta por NOMBRE DE PROPIEDAD BINARIA (options.attachments = "data"),
// no aceptando un array de objetos {name, content, contentType}. Este nodo
// solo decide si hay adjunto y reenvia el binario intacto.

const item = $input.first();
const j = item.json || {};

if (!j.success || !item.binary || !item.binary.data) {
  return [{ json: { success: true, has_attachment: false, audio_file: null } }];
}

return [{
  json: {
    success: true,
    has_attachment: true,
    audio_file: j.audio_filename
  },
  binary: { data: item.binary.data }
}];

const item = $input.first();
// BUG ORIGINAL: "const data = $input.first(); ... data.body" leia el wrapper
// del item (que NO tiene .body), nunca el payload real -> todo caia en los
// valores por defecto (incluido conversation_id -> "AUTO_...") sin importar
// lo que mandara el webhook de ElevenLabs. El payload real vive en item.json.body.
const rawBody = (item.json && item.json.body !== undefined) ? item.json.body : item.json;
const payload = typeof rawBody === "string" ? JSON.parse(rawBody) : rawBody;

// Soporta el webhook post-call REAL de ElevenLabs (analysis.data_collection_results
// + metadata + transcript) ademas del payload plano simple (test / integracion
// directa). Nunca se inventan datos: si un campo no llega, se usa un fallback
// generico marcado como tal via los valores por defecto de mas abajo.
const analysis = payload.analysis || {};
const dc = analysis.data_collection_results || {};
const meta = payload.metadata || {};

function dcv(k) {
  const o = dc[k] != null ? dc[k] : (dc[k + "  "] != null ? dc[k + "  "] : dc[k + " "]);
  if (o == null) return undefined;
  return (typeof o === "object" && "value" in o) ? o.value : o;
}
function pick() {
  for (let i = 0; i < arguments.length; i++) {
    const v = arguments[i];
    if (v !== undefined && v !== null && v !== "") return v;
  }
  return undefined;
}

const now = new Date();
const dia = String(now.getDate()).padStart(2, "0");
const mes = String(now.getMonth() + 1).padStart(2, "0");
const anio = now.getFullYear();

console.log("DEBUG - Webhook payload:", JSON.stringify(payload, null, 2));

// --- Identidad (FIX: antes solo se calculaba employee_name; nombre/empleado_id/
// puesto no existian en la salida, por lo que "Generar HTML Email" SIEMPRE
// mostraba los valores de ejemplo fijos de su plantilla, sin importar el payload) ---
const nombre = pick(payload.nombre, dcv("user_name"), payload.employee_name) || "Usuario";
const empleadoId = pick(payload.empleado_id, payload.employee_number, dcv("employee_number"), payload.emp_id) || "0000";
const puesto = pick(payload.puesto, dcv("user_role"), payload.role) || "Asesor de Ventas";
const departamento = pick(payload.departamento, payload.dept) || "Dirección de Ventas";
function normalizaIdioma(v) {
  const s = String(v || "").toLowerCase();
  if (!s) return undefined;
  if (s.indexOf("esp") === 0 || s === "es") return "Español";
  if (s.indexOf("ing") === 0 || s.indexOf("en") === 0) return "Inglés";
  return v;
}
const idioma = normalizaIdioma(pick(payload.idioma, dcv("idioma"))) ||
  ((meta.main_language || "").toLowerCase().indexOf("en") === 0 ? "Inglés" : "Español");

const durSecsFromMeta = meta.call_duration_secs;
const duracionMinutos = payload.duracion_minutos || (durSecsFromMeta ? Math.round(durSecsFromMeta / 60) : 28);
const durSecs = durSecsFromMeta || (payload.duracion_minutos ? payload.duracion_minutos * 60 : duracionMinutos * 60);
const duracionTexto = payload.duracion_texto || (durSecs ? (Math.floor(durSecs / 60) + ":" + String(Math.round(durSecs % 60)).padStart(2, "0")) : "28:00");

const scoreTotal = Number(pick(payload.scoreTotal, payload.score, dcv("desempeno_score"))) || 8.7;
const potencialMejora = payload.potencial_mejora != null ? payload.potencial_mejora : Math.max(0, Math.round((10 - scoreTotal) * 13));

return {
    success: true,
    conversation_id: payload.conversation_id || "AUTO_" + Date.now(),

    // Identidad
    employee_name: nombre,
    nombre: nombre,
    empleado_id: empleadoId,
    puesto: puesto,
    departamento: departamento,
    idioma: idioma,

    // Métricas (0-10)
    score: payload.scoreTotal || payload.score || 0,
    scoreTotal: scoreTotal,
    rapport: Number(payload.rapport) || 8.5,
    pnl: Number(payload.pnl) || 8.7,
    postura: Number(payload.postura) || 7.7,
    objeciones: Number(payload.objeciones) || 8.2,
    cierre: Number(payload.cierre) || 7.0,
    escucha: Number(payload.escucha) || 9.0,
    potencial_mejora: potencialMejora,

    // Narrativa
    resumen: pick(payload.resumen, analysis.transcript_summary, dcv("recomendacion_siguiente")) || "Sesión completada.",
    fortalezas: pick(payload.fortalezas, dcv("fortalezas")) || "Buena disposición y actitud durante la práctica.",
    areas_mejora: pick(payload.areas_mejora, dcv("areas_mejora")) || "Reforzar los fundamentos del módulo practicado.",
    analisis_pnl: payload.analisis_pnl || "Sin patrones PNL destacados en esta sesión.",
    recomendacion_siguiente: pick(payload.recomendacion_siguiente, dcv("recomendacion_siguiente")) || "Repasar el módulo con menor puntaje.",

    // Escenario / módulos
    escenario: pick(payload.escenario, dcv("escenario_roleplay"), dcv("tipo_actividad")) || "Sesión de coaching",
    tipo_actividad: pick(payload.tipo_actividad, dcv("tipo_actividad")) || "Roleplay",
    modulos_practicados: pick(payload.modulos_practicados, dcv("modulos_practicados")) || "",

    // Fecha / hora / duración
    fecha_formato: payload.fecha_formato || `${dia}-${mes}-${anio}`,
    hora_inicio: payload.hora_inicio || "14:35",
    hora_fin: payload.hora_fin || "15:03",
    duracion_minutos: duracionMinutos,
    duracion_texto: duracionTexto,
    sesion_numero: payload.sesion_numero || 1,

    // Plan de acción (gerente)
    accion1: payload.accion1 || "Reducir Interrupciones",
    accion1_desc: payload.accion1_desc || "Pausas prolongadas entre argumentos.",
    accion2: payload.accion2 || "Memorizar el Pitch",
    accion2_desc: payload.accion2_desc || "Dudar en el pitch resta credibilidad.",
    accion3: payload.accion3 || "Dominar el Cierre",
    accion3_desc: payload.accion3_desc || "Falta de confianza al cerrar.",

    // Frecuencia de temas (escala 0-10)
    precio: payload.precio != null ? payload.precio : 8,
    incentivos: payload.incentivos != null ? payload.incentivos : 6,
    tiempo: payload.tiempo != null ? payload.tiempo : 10,
    indecision: payload.indecision != null ? payload.indecision : 4,

    // Distribución de tiempo por actividad (%, deben sumar ~100)
    pct_pitch: payload.pct_pitch != null ? payload.pct_pitch : 50,
    pct_warmup: payload.pct_warmup != null ? payload.pct_warmup : 20,
    pct_objeciones: payload.pct_objeciones != null ? payload.pct_objeciones : 15,
    pct_cierre: payload.pct_cierre != null ? payload.pct_cierre : 15,

