    <tr><td style="padding:0 0 13px 0;"><table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#262626;border-radius:99px;"><tr>
    <td style="font-size:0;line-height:0;"><table width="${w}%" cellpadding="0" cellspacing="0" border="0"><tr>
    <td height="6" style="background:${colorHex};border-radius:99px;font-size:0;line-height:0;">&nbsp;</td></tr></table></td></tr></table></td></tr>`;
