// ---- Bloques opcionales: solo se pintan si hay datos REALES --------------
// Regla de precisión (ver feedback_research_accuracy): nunca se inventan
// transcripciones, quiz u objeciones de ejemplo para una sesión real. Si el
// payload no trae esos arreglos, la sección se omite en vez de mostrar
// contenido ficticio.

function buildHistorialRows(d) {
  const hist = Array.isArray(d.historial) ? d.historial.filter(h => h && h.fecha) : [];
  const rows = [...hist];
  rows.push({ fecha: fechaDisplayShort(d.fecha_formato), sesion_num: d.sesion_numero, score: d.scoreTotal, current: true });
  const maxScore = 10;
  return rows.map(h => {
    const pct = Math.max(4, Math.round((num(h.score, 0) / maxScore) * 100));
    const barColor = h.current ? "#EAB308" : "#8a7530";
    const txtColor = h.current ? "#FFFFFF" : "#a3a3a3";
    const scoreColor = h.current ? "#EAB308" : "#a3a3a3";
    const weight = h.current ? "font-weight:600;" : "";
    return `<tr><td style="padding:0 0 10px 0;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr>
      <td width="150" style="font-family:Inter,sans-serif;font-size:12px;color:${txtColor};${weight}">${esc(h.fecha)}${h.sesion_num ? " · Sesión " + esc(h.sesion_num) : ""}</td>
      <td style="padding:0 12px;"><table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#262626;border-radius:99px;"><tr><td style="font-size:0;line-height:0;"><table width="${pct}%" cellpadding="0" cellspacing="0" border="0"><tr><td height="6" style="background:${barColor};border-radius:99px;font-size:0;line-height:0;">&nbsp;</td></tr></table></td></tr></table></td>
      <td width="46" align="right" style="font-family:Montserrat,sans-serif;font-weight:700;font-size:14px;color:${scoreColor};">${scoreStr(num(h.score,0))}</td>
      </tr></table></td></tr>`;
  }).join("");
}
function fechaDisplayShort(fecha_formato) {
  const m = /^(\d{2})-(\d{2})-(\d{4})$/.exec(fecha_formato || "");
  if (!m) return esc(fecha_formato || "");
  return `${m[1]}-${m[2]}-${m[3]}`;
}

function buildTranscriptHTML(d) {
  const turns = Array.isArray(d.transcript) ? d.transcript : [];
  if (!turns.length) {
    return `<div style="font-family:Inter,sans-serif;font-size:13px;line-height:20px;color:#6a6a6a;padding:8px 0;">Transcripción no disponible para esta sesión.</div>`;
  }
  return turns.map(t => {
    const isVictor = String(t.role || t.speaker || "").toLowerCase().indexOf("victor") !== -1 || String(t.role||"").toLowerCase()==="agent";
    const align = isVictor ? "left" : "right";
    const bg = isVictor ? "#161410" : "#14131a";
    const border = isVictor ? "#2a2620" : "#2a2740";
    const tagColor = isVictor ? "#EAB308" : "#9b8cff";
    const tag = isVictor ? "VÍCTOR" : "ASESOR";
    let timeRaw = t.time || t.timestamp;
    if (!timeRaw && t.time_in_call_secs != null) {
      const s = Number(t.time_in_call_secs) || 0;
      timeRaw = `+${Math.floor(s / 60)}:${String(Math.round(s % 60)).padStart(2, "0")}`;
    }
    const time = esc(timeRaw || "");
    const msg = esc(t.text || t.message || "");
    return `<tr><td style="padding:0 0 12px 0;">
      <table role="presentation" width="82%" align="${align}" cellpadding="0" cellspacing="0" border="0" style="background:${bg};border:1px solid ${border};border-radius:14px;">
        <tr><td style="padding:13px 17px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"><tr>
          <td style="font-family:Inter,sans-serif;font-size:10px;letter-spacing:2px;color:${tagColor};font-weight:700;">${tag}</td>
          <td align="right" style="font-family:Inter,sans-serif;font-size:10px;color:#5a5a62;letter-spacing:0.5px;">${time}</td>
        </tr></table><div style="height:6px;font-size:0;">&nbsp;</div><div style="font-family:Inter,sans-serif;font-size:14px;line-height:22px;color:#dcdce2;">${msg}</div></td></tr>
      </table><div style="clear:both;font-size:0;line-height:0;">&nbsp;</div>
    </td></tr>`;
  }).join("");
}

function buildQuizHTML(d) {
  const quiz = Array.isArray(d.quiz) ? d.quiz : [];
  if (!quiz.length) return null;
  return quiz.map((q, i) => {
    const correct = !!q.correcto;
    const badge = correct
      ? `<span style="display:inline-block;font-family:Inter,sans-serif;font-size:10px;letter-spacing:1.5px;font-weight:700;text-transform:uppercase;padding:5px 12px;border-radius:99px;background:rgba(92,192,138,0.15);color:#5cc08a;">✓ Correcto</span>`
      : `<span style="display:inline-block;font-family:Inter,sans-serif;font-size:10px;letter-spacing:1.5px;font-weight:700;text-transform:uppercase;padding:5px 12px;border-radius:99px;background:rgba(224,131,111,0.15);color:#e0836f;">✗ Incorrecto</span>`;
  return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#171717;border:1px solid #262626;border-radius:12px;margin-bottom:14px;"><tr><td style="padding:20px 22px;">
      <div style="font-family:Inter,sans-serif;font-size:14px;line-height:21px;color:#FFFFFF;font-weight:600;">${i + 1}. ${esc(q.pregunta)}</div>
      <div style="height:10px;font-size:0;">&nbsp;</div>
      <table width="100%" cellpadding="0" cellspacing="0" border="0"><tr>
        <td style="font-family:Inter,sans-serif;font-size:13px;color:#a3a3a3;padding:0 0 4px 0;">Tu respuesta: <span style="color:#E5E5E5;">${esc(q.respuesta)}</span></td>
