      </tr></table>
      ${badge}
      ${q.nota ? `<div style="height:10px;font-size:0;">&nbsp;</div><div style="font-family:Inter,sans-serif;font-size:13px;line-height:20px;color:#a3a3a3;">${esc(q.nota)}</div>` : ""}
    </td></tr></table>`;
  }).join("");
